CREATE TABLE "api"."webhook_event_deliveries" ("id" uuid NOT NULL DEFAULT gen_random_uuid(), "created_at" timestamptz NOT NULL DEFAULT now(), "response_status" integer NOT NULL, "response_text" text NOT NULL, "response_headers" Text NOT NULL, "request_headers" text NOT NULL, "status" text NOT NULL, "webhook_event_id" uuid NOT NULL, "attempt_number" integer NOT NULL, PRIMARY KEY ("id") , FOREIGN KEY ("webhook_event_id") REFERENCES "api"."webhook_events"("id") ON UPDATE restrict ON DELETE cascade, UNIQUE ("webhook_event_id", "attempt_number"));COMMENT ON TABLE "api"."webhook_event_deliveries" IS E'These rows should be write-once. Update never.';
CREATE EXTENSION IF NOT EXISTS pgcrypto;
